    const choice = await ui.prompt('[Press Enter when done, or s to skip]');

    if (choice.toLowerCase() === 's') {
      ui.warn('Skipped. You can set up Tailscale later.');
      await ui.sleep(1500);
      return;
    }

    // Verify authentication
    ui.text('Checking Tailscale status...');
    await ui.sleep(1000);

    const status = checkTailscale();

    if (status.authenticated) {
      ui.blank();
      ui.success('Tailscale connected!');
      ui.text(`Your Tailscale IP: ${status.details}`);
      ui.blank();
      ui.text('Now you can SSH to this machine from any device');
      ui.text('with Tailscale installed.');
      ui.blank();

      await ui.prompt('[Press Enter to continue]');
    } else {
      ui.blank();
      ui.warn('Tailscale not yet connected.');
      ui.text('You can try again or set it up later.');

      const retry = await ui.prompt('[r to retry, Enter to continue]');
      if (retry.toLowerCase() === 'r') {
        return this.run(ui);  // Recursive retry
      }
    }
  },
};
```

## UI Framework

Use a simple TUI framework. Options:
- `blessed` - Classic Node.js TUI
- `ink` - React for CLIs
- `prompts` - Simple and lightweight

Recommend `prompts` + custom rendering for simplicity:

```typescript
// packages/onboard/src/ui.ts

import prompts from 'prompts';
import chalk from 'chalk';

export class UI {
  clear() {
    console.clear();
  }

  header(text: string) {
    console.log(chalk.bold.blue(`\n${'═'.repeat(60)}`));
    console.log(chalk.bold.blue(`  ${text}`));
    console.log(chalk.bold.blue(`${'═'.repeat(60)}\n`));
  }

  text(text: string) {
    console.log(text);
  }

  blank() {
    console.log();
  }

  code(text: string) {
    console.log(chalk.bgGray.white(`  ${text}  `));
  }

  success(text: string) {
    console.log(chalk.green(`✓ ${text}`));
  }

  warn(text: string) {
    console.log(chalk.yellow(`⚠ ${text}`));
  }

  async prompt(message: string): Promise<string> {
    const response = await prompts({
      type: 'text',
      name: 'value',
      message,
    });
    return response.value || '';
  }

  async sleep(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}
